window.__QUIZ_DATA__=[{"id":"objective>Economics>1993>1","subject":"Economics","year":"1993","type":"Objective","topic":"INTRODUCTION TO ECONOMICS : BASIC CONCEPT OF ECONOMICS","question":"Economics is the study of how to","images":[],"options":{"A":"choose between alternatives, given limited resources","B":"regulate the money that is in circulation in a country","C":"be prudent in the use of available resources","D":"improve the standard of living of the society at large"},"answer":"A","explanation":"Economics is fundamentally about making choices between alternatives due to limited resources. This concept is known as opportunity cost, which emphasizes that every choice has a trade-off.","marks":"1","difficulty":"1"},{"id":"objective>Economics>1993>2","subject":"Economics","year":"1993","type":"Objective","topic":"INTRODUCTION TO ECONOMICS : BASIC CONCEPT OF ECONOMICS","question":"Scarcity in Economics arises because","images":[],"options":{"A":"the resources available are adequate","B":"individuals have limited time","C":"resources are limited in supply","D":"human beings have limited wants"},"answer":"C","explanation":"Scarcity in economics arises because resources are limited in supply while human wants are virtually unlimited. This fundamental economic problem forces individuals and societies to make choices about how to allocate their limited resources.","marks":"1","difficulty":"1"},{"id":"objective>Economics>1993>3","subject":"Economics","year":"1993","type":"Objective","topic":"THE CONCEPT OF COST & REVENUE : CONCEPT","question":"The real cost of a commodity is","images":[],"options":{"A":"the cost of the alternative that has to be sacrificed for it","B":"the alternative that has to be forgone in order to purchase it","C":"its market price","D":"the alternative cost involved when the opportunity of buying the commodity is missed"},"answer":"A","explanation":"The real cost of a commodity is defined as the opportunity cost, which is the cost of the alternative that has to be sacrificed in order to obtain it. This concept highlights the trade-offs involved in economic decision-making.","marks":"1","difficulty":"2"},{"id":"objective>Economics>1993>4","subject":"Economics","year":"1993","type":"Objective","topic":"BUSINESS ORGANISATION : PUBLIC CORPORATIONS","question":"Public corporations in West Africa are set up to","images":[],"options":{"A":"make maximum profit","B":"provide jobs for the people","C":"provide welfare services for the people","D":"show that the government can do business"},"answer":"C","explanation":"Public corporations in West Africa are typically established to provide welfare services for the people, rather than to maximize profit. They aim to serve the public interest and address social needs.","marks":"1","difficulty":"2"},{"id":"objective>Economics>1993>5","subject":"Economics","year":"1993","type":"Objective","topic":"THEORY OF SUPPLY : MEANING AND DETERMINANTS","question":"Supply in Economics means making","images":[],"options":{"A":"goods and services available to consumers","B":"goods available to the market at a given price and at a given period","C":"available the goods and services which consumers require","D":"the circulation of goods"},"answer":"B","explanation":"In economics, supply refers to the quantity of goods available to the market at a given price and at a given period. This definition captures the essence of supply as it relates to market dynamics.","marks":"1","difficulty":"1"},{"id":"objective>Economics>1993>6","subject":"Economics","year":"1993","type":"Objective","topic":"THE THEORY OF DEMAND : ELASTICITY OF DEMAND","question":"An inferior good is one","images":[],"options":{"A":"that is too bad for consumption","B":"whose price is lower than the prices of other goods","C":"that is easily perishable","D":"whose demand falls when the income of its consumers increases"},"answer":"D","explanation":"An inferior good is defined as a type of good whose demand increases when consumer incomes fall, and conversely, whose demand decreases when consumer incomes rise. Therefore, the correct option is that an inferior good is one whose demand falls when the income of its consumers increases.","marks":"1","difficulty":"2"},{"id":"objective>Economics>1993>7","subject":"Economics","year":"1993","type":"Objective","topic":"THE THEORY OF DEMAND : ELASTICITY OF DEMAND","question":"Price elasticity of demand is defined as the","images":[],"options":{"A":"responsiveness of demand to changes in price","B":"responsiveness of price to change in demand","C":"increase in demand resulting from a rise in price","D":"unit decrease in price resulting from a fall in demand"},"answer":"A","explanation":"Price elasticity of demand measures how much the quantity demanded of a good responds to a change in the price of that good. It is defined as the responsiveness of demand to changes in price.","marks":"1","difficulty":"2"},{"id":"objective>Economics>1993>8","subject":"Economics","year":"1993","type":"Objective","topic":"AGRICULTURE IN WEST AFRICA : INTRODUCTION","question":"The rural areas of West African countries lack industries because","images":[],"options":{"A":"rural people are not meant to work in industries","B":"rural people are uneducated","C":"of inadequate infrastructure","D":"of low population density"},"answer":"C","explanation":"The lack of industries in rural areas of West African countries is primarily due to inadequate infrastructure. This includes poor transportation, lack of utilities, and insufficient facilities that are necessary for industrial development. Therefore, option 3 is correct.","marks":"1","difficulty":"2"},{"id":"objective>Economics>1993>9","subject":"Economics","year":"1993","type":"Objective","topic":"BUSINESS ORGANISATION : INTRODUCTION","question":"An entrepreneur will locate his industry in a place","images":[],"options":{"A":"nearest to his home town","B":"where the cost of production will be minimized","C":"nearest to his wife's home town","D":"where the government directs him to locate it"},"answer":"B","explanation":"An entrepreneur typically locates their industry where the cost of production will be minimized. This is crucial for maximizing profits and ensuring the sustainability of the business. Thus, option 2 is the correct answer.","marks":"1","difficulty":"2"},{"id":"objective>Economics>1993>10","subject":"Economics","year":"1993","type":"Objective","topic":"THEORY OF PRODUCTION : LAWS OF PRODUCTION","question":"Which important economic principle is illustrated by the graph above","images":["data:image/jpeg;base64,"],"options":{"A":"Law of Comparative Cost","B":"Law of Diminishing Marginal Utility","C":"Law of Diminishing Returns","D":"Malthusian Law of Population"},"answer":"C","explanation":"The graph illustrates the law of diminishing returns which is also known as the law of variable proportion. The law is applied to the short run analysis is production which shows the relationship between total product and marginal product.","marks":"1","difficulty":"3"},{"id":"objective>Economics>1993>11","subject":"Economics","year":"1993","type":"Objective","topic":"DISTRIBUTIVE TRADE : THE MIDDLEMEN","question":"Which of the following reasons is mainly responsible for the inefficient distribution of goods in West African countries? The","images":[],"options":{"A":"large number of distribution companies","B":"import and export restrictions by the government","C":"narrow market for commodities produced","D":"poor transport and communication systems"},"answer":"D","explanation":"The poor transport and communication systems in West African countries significantly hinder the efficient distribution of goods. These systems are crucial for moving products from producers to consumers, and inefficiencies in these areas can lead to delays, increased costs, and ultimately, an inability to meet market demand effectively.","marks":"1","difficulty":"2"},{"id":"objective>Economics>1993>12","subject":"Economics","year":"1993","type":"Objective","topic":"BUSINESS ORGANISATION : LIMITED LIABILITY COMPANIES","question":"Which of the following does not apply to private companies?","images":[],"options":{"A":"The number of shareholders is limited","B":"The liability of shareholders is limited","C":"Accounts have to be publicized","D":"The companies are separate legal entities"},"answer":"C","explanation":"Private companies are not required to publicize their accounts, which is a key distinction from public companies. Public companies must disclose financial information to the public to ensure transparency for shareholders and potential investors, while private companies have more privacy regarding their financial affairs.","marks":"1","difficulty":"2"},{"id":"objective>Economics>1993>13","subject":"Economics","year":"1993","type":"Objective","topic":"LABOUR MARKET AND UNEMPLOYMENT : DEMAND FOR LABOUR","question":"In Economics, the reward for labour is in the form of","images":[],"options":{"A":"wages","B":"profit","C":"rent","D":"dividends"},"answer":"A","explanation":"In Economics, the reward for labor is typically in the form of wages. Wages are the compensation paid to workers for their labor, reflecting the value of their work in the production process.","marks":"1","difficulty":"1"},{"id":"objective>Economics>1993>14","subject":"Economics","year":"1993","type":"Objective","topic":"POPULATION : OVER POPULATION, UNDER POPULATION","question":"A nation with a working population that is insufficient to exploit its resources is said to be","images":[],"options":{"A":"over -populated","B":"under-populated","C":"experiencing decreasing population","D":"experiencing increasing population"},"answer":"B","explanation":"A nation with a working population that is insufficient to exploit its resources is described as under-populated. This means that there are not enough people to utilize the available resources effectively, leading to potential economic inefficiencies.","marks":"1","difficulty":"2"},{"id":"objective>Economics>1993>15","subject":"Economics","year":"1993","type":"Objective","topic":"THEORY OF PRODUCTION : CONCEPTS OF PRODUCTION","question":"Which of the following may not be included in explaining the term production?","images":[],"options":{"A":"Provision of services","B":"Manufacture of goods","C":"Changing raw materials to finished goods","D":"Use of consumer goods"},"answer":"D","explanation":"The use of consumer goods is not typically included in the definition of production. Production generally refers to the processes involved in creating goods and services, while consumer goods are the end products that result from production processes.","marks":"1","difficulty":"2"},{"id":"objective>Economics>1993>16","subject":"Economics","year":"1993","type":"Objective","topic":"BUSINESS ORGANISATION : CO-OPERATIVE SOCIETIES","question":"Which of the following business establishments are not motivated mainly by profit?","images":[],"options":{"A":"Public Limited Companies","B":"Private Limited Companies","C":"Partnerships","D":"Co-operatives"},"answer":"D","explanation":"Co-operatives are business establishments that are not primarily motivated by profit. Instead, they are formed to meet the needs of their members, who are also the owners. This contrasts with profit-driven entities like public and private limited companies.","marks":"1","difficulty":"2"},{"id":"objective>Economics>1993>17","subject":"Economics","year":"1993","type":"Objective","topic":"DISTRIBUTIVE TRADE : THE WHOLESALER","question":"Production is not complete until the","images":[],"options":{"A":"goods get to the wholesalers","B":"goods reach the final consumer","C":"factors of production are combined","D":"goods are ready for transportation"},"answer":"B","explanation":"Production is considered complete when goods reach the final consumer. This is because the ultimate goal of production is to satisfy consumer needs, and until the goods are in the hands of the consumer, the production process is not fully realized.","marks":"1","difficulty":"2"},{"id":"objective>Economics>1993>18","subject":"Economics","year":"1993","type":"Objective","topic":"THE CONCEPT OF COST & REVENUE : CONCEPT","question":"Which of the following is the correct way to calculate total cost?","images":[],"options":{"A":"Addition of fixed cost to variable cost","B":"Division of total cost by total output","C":"Multiplication of fixed cost by variable cost","D":"Subtraction of fixed cost from total cost"},"answer":"A","explanation":"Total cost is calculated by adding fixed costs to variable costs. Fixed costs are expenses that do not change with the level of output, while variable costs fluctuate with production levels. Together, they represent the total expenditure incurred in the production process.","marks":"1","difficulty":"2"},{"id":"objective>Economics>1993>19","subject":"Economics","year":"1993","type":"Objective","topic":"POPULATION : THEORIES OF POPULATION","question":"Robert T. Malthus postulated in his population theory that","images":[],"options":{"A":"the death rate may become so high that people may not survive","B":"people will migrate from one place to another in search of food","C":"positive efforts should be made to increase population","D":"population growth rate may out-grow the means of subsistence"},"answer":"D","explanation":"Robert T. Malthus postulated in his population theory that population growth tends to outpace food production, leading to inevitable checks on population such as famine, disease, and war.","marks":"1","difficulty":"2"},{"id":"objective>Economics>1993>20","subject":"Economics","year":"1993","type":"Objective","topic":"THEORY OF PRODUCTION : DIVISION OF LABOUR AND SPECIALISATION","question":"Division of labour may be restricted when","images":[],"options":{"A":"an ailing economy has improved","B":"producers live in villages","C":"market is small","D":"there is full employment"},"answer":"C","explanation":"Division of labour may be restricted when the market is small. A small market limits the demand for goods, which in turn restricts the extent to which tasks can be divided among workers, as there may not be enough work to justify specialization.","marks":"1","difficulty":"2"},{"id":"objective>Economics>1993>21","subject":"Economics","year":"1993","type":"Objective","topic":"THEORY OF PRODUCTION : FACTORS OF PRODUCTION","question":"Land is often distinguished as a factor of production because it","images":[],"options":{"A":"is a free gift of nature","B":"constitutes one -third of the entire world","C":"is unlimited in supply","D":"is owned by individuals"},"answer":"A","explanation":"Land is distinguished as a factor of production because it is considered a free gift of nature. Unlike labor and capital, which require human effort and investment, land is naturally occurring and provides the resources necessary for production.","marks":"1","difficulty":"1"},{"id":"objective>Economics>1993>22","subject":"Economics","year":"1993","type":"Objective","topic":"THEORY OF PRODUCTION : DIVISION OF LABOUR AND SPECIALISATION","question":"Which of the following is not an advantage of division of labour? It","images":[],"options":{"A":"saves time","B":"makes possible the use of machines","C":"is monotonous","D":"leads to specialization"},"answer":"C","explanation":"The option 'is monotonous' is not an advantage of division of labour. While division of labour increases efficiency and productivity by allowing workers to specialize in specific tasks, it can also lead to monotony and a lack of job satisfaction due to repetitive tasks.","marks":"1","difficulty":"2"},{"id":"objective>Economics>1993>23","subject":"Economics","year":"1993","type":"Objective","topic":"AGRICULTURE IN WEST AFRICA : FEATURES","question":"The location of timber and plywood industries in West Africa is mainly influenced by the","images":[],"options":{"A":"availability of transport","B":"availability of power supply","C":"adequate labour supply","D":"presence of a luxuriant forest"},"answer":"D","explanation":"The presence of a luxuriant forest is the primary factor influencing the location of timber and plywood industries in West Africa. These industries rely heavily on the availability of raw materials, which in this case are trees from forests.","marks":"1","difficulty":"2"},{"id":"objective>Economics>1993>24","subject":"Economics","year":"1993","type":"Objective","topic":"POPULATION : DETERMINANTS OF POPULATION SIZE","question":"The occupational distribution of population in most West African countries shows the highest concentration in","images":[],"options":{"A":"agriculture and allied industries","B":"mining and manufacturing","C":"the distributive trade","D":"commerce and industry"},"answer":"A","explanation":"The occupational distribution of population in most West African countries shows the highest concentration in agriculture and allied industries. This is due to the agrarian nature of many West African economies, where a significant portion of the population is engaged in farming and related activities.","marks":"1","difficulty":"2"},{"id":"objective>Economics>1993>25","subject":"Economics","year":"1993","type":"Objective","topic":"POPULATION : INTRODUCTION","question":"The growth rate of population is the","images":[],"options":{"A":"annual increase in population","B":"addition to the total population over a given period","C":"increase in the working population over a given period","D":"percentage increase in population in a given year"},"answer":"D","explanation":"The growth rate of population is defined as the percentage increase in population in a given year. This metric helps to understand how quickly a population is growing relative to its size.","marks":"1","difficulty":"1"},{"id":"objective>Economics>1993>26","subject":"Economics","year":"1993","type":"Objective","topic":"THE THEORY OF DEMAND : TYPES OF DEMAND","question":"A situation in which an increase in the demand for certain goods leads to a fall in the demand for other goods is known as","images":[],"options":{"A":"joint supply","B":"derived demand","C":"competitive demand","D":"competitive supply"},"answer":"C","explanation":"The situation where an increase in the demand for certain goods leads to a fall in the demand for other goods is known as competitive demand. This occurs when goods are substitutes for each other, meaning that as one becomes more desirable, the other becomes less so.","marks":"1","difficulty":"2"},{"id":"objective>Economics>1993>27","subject":"Economics","year":"1993","type":"Objective","topic":"THE THEORY OF PRICE DETERMINATION : CONCEPT OF MARKET AND PRICE","question":"A market equilibrium exists when","images":[],"options":{"A":"demand and supply are equal","B":"the market is large","C":"the price is fluctuating","D":"no buyers goes home empty-handed"},"answer":"A","explanation":"A market equilibrium exists when demand and supply are equal. This is the fundamental principle of market equilibrium, where the quantity of goods supplied matches the quantity of goods demanded at a certain price level.","marks":"1","difficulty":"1"},{"id":"objective>Economics>1993>28","subject":"Economics","year":"1993","type":"Objective","topic":"THE THEORY OF PRICE DETERMINATION : CONCEPT OF MARKET AND PRICE","question":"The price system is","images":[],"options":{"A":"the market price of commodities","B":"a market where a single price rules","C":"a system of price allocation to the products of the same firm","D":"a system of resource allocation through supply and demand interactions"},"answer":"D","explanation":"The price system is a system of resource allocation through supply and demand interactions. It reflects how prices are determined in a market economy based on the interaction between buyers and sellers, which influences the distribution of resources.","marks":"1","difficulty":"2"},{"id":"objective>Economics>1993>29","subject":"Economics","year":"1993","type":"Objective","topic":"THEORY OF PRODUCTION : CONCEPTS OF PRODUCTION","question":"The main objective of production by an entrepreneur is to","images":[],"options":{"A":"equate marginal revenue with marginal cost","B":"provide employment opportunities","C":"equate total revenue with total cost","D":"equate average revenue with average cost"},"answer":"A","explanation":"The main objective of production by an entrepreneur is to equate marginal revenue with marginal cost. This is a key principle in economics where firms maximize profit by producing up to the point where the additional revenue from selling one more unit equals the additional cost of producing that unit.","marks":"1","difficulty":"2"},{"id":"objective>Economics>1993>30","subject":"Economics","year":"1993","type":"Objective","topic":"THEORY OF SUPPLY : DISTINCTION BETWEEN CHANGE IN QUANTITY SUPPLIED AND CHANGE IN SUPPLY","question":"If price falls below the equilibrium","images":[],"options":{"A":"demand will equal supply","B":"demand will be greater than supply","C":"supply will be greater than demand","D":"price will become indeterminate"},"answer":"B","explanation":"If price falls below the equilibrium, demand will be greater than supply. This situation creates a shortage in the market, as consumers want to buy more at the lower price, but producers are not willing to supply enough at that price.","marks":"1","difficulty":"2"},{"id":"objective>Economics>1993>31","subject":"Economics","year":"1993","type":"Objective","topic":"BUSINESS ORGANISATION : SOLE PROPRIETOSHIP","question":"Which of the following is not a source of finance for a one-man business?","images":[],"options":{"A":"Money lenders","B":"Loans from insurance companies","C":"Loans from banks","D":"Sale of shares"},"answer":"D","explanation":"The sale of shares is not a source of finance for a one-man business because a one-man business typically does not issue shares. Shares are associated with corporations or partnerships where ownership is divided among multiple shareholders.","marks":"1","difficulty":"2"},{"id":"objective>Economics>1993>32","subject":"Economics","year":"1993","type":"Objective","topic":"AGRICULTURE IN WEST AFRICA : FEATURES","question":"Land is a most significant factor in terms of contribution to the economy because","images":[],"options":{"A":"it enables us to build industries","B":"all our highways are constructed on it","C":"we get a lot of fishes from it","D":"vital resources from it enrich the economy"},"answer":"D","explanation":"Land is a significant factor in the economy because it provides vital resources such as minerals, agricultural products, and timber, which enrich the economy. These resources are essential for various industries and contribute to economic growth.","marks":"1","difficulty":"2"},{"id":"objective>Economics>1993>33","subject":"Economics","year":"1993","type":"Objective","topic":"THEORY OF PRODUCTION : FACTORS OF PRODUCTION","question":"Capital as a factor of production is important because","images":[],"options":{"A":"it enables us to carry out tasks which cannot be done by human effort only","B":"most tasks can be done with bare hands","C":"people can work without capital","D":"without capital all other factors are useless"},"answer":"A","explanation":"Capital as a factor of production is important because it enables us to carry out tasks that cannot be done by human effort alone. For example, machinery and technology (forms of capital) enhance productivity and efficiency in production processes.","marks":"1","difficulty":"2"},{"id":"objective>Economics>1993>34","subject":"Economics","year":"1993","type":"Objective","topic":"THE CONCEPT OF COST & REVENUE : CONCEPT","question":"A firm's compulsory cost whether it is in production or not, is referred to as its","images":[],"options":{"A":"prime cost","B":"variable cost","C":"marginal cost","D":"fixed cost"},"answer":"D","explanation":"A firm's compulsory cost, whether it is in production or not, is referred to as its fixed cost. Fixed costs are expenses that do not change with the level of output, such as rent and salaries, and must be paid regardless of production levels.","marks":"1","difficulty":"2"},{"id":"objective>Economics>1993>35","subject":"Economics","year":"1993","type":"Objective","topic":"THEORY OF CONSUMER BEHAVIOUR : CONCEPT","question":"A scale of preference is a list","images":[],"options":{"A":"of consumer's wants arranged in order of importance","B":"that helps the individual to make a rational choice","C":"that enables the consumers to make a wise decision about his choice","D":"that is necessary because human beings are faced eith competing wants"},"answer":"A","explanation":"A scale of preference is a list of consumer's wants arranged in order of importance. It helps individuals prioritize their needs and make rational choices based on limited resources.","marks":"1","difficulty":"2"},{"id":"objective>Economics>1993>36","subject":"Economics","year":"1993","type":"Objective","topic":"ECONOMIC SYSTEM : TYPES AND FEATURES OF ECONOMIC SYSTEM","question":"An economic system in which the state owns and controls the means of production is known as","images":[],"options":{"A":"free enterprise","B":"socialist economy","C":"mixed economy","D":"capitalist economy"},"answer":"B","explanation":"An economic system in which the state owns and controls the means of production is known as a socialist economy. In this system, the government typically manages resources and production to promote equality and meet the needs of the population.","marks":"1","difficulty":"3"},{"id":"objective>Economics>1993>37","subject":"Economics","year":"1993","type":"Objective","topic":"DISTRIBUTIVE TRADE : THE MIDDLEMEN","question":"Which of the following is not a middleman in the distribution channel? The","images":[],"options":{"A":"wholesaler","B":"distributor","C":"agent","D":"consumer"},"answer":"D","explanation":"The consumer is not a middleman in the distribution channel. Middlemen, such as wholesalers, distributors, agents, and retailers, facilitate the movement of goods from producers to consumers. The consumer is the end-user of the product and does not play a role in the distribution process.","marks":"1","difficulty":"2"},{"id":"objective>Economics>1993>38","subject":"Economics","year":"1993","type":"Objective","topic":"THEORY OF PRODUCTION : DIVISION OF LABOUR AND SPECIALISATION","question":"Division of labour gives rise to","images":[],"options":{"A":"the exchange of goods and services","B":"the use of a barter system","C":"the production of limited good","D":"unemployment"},"answer":"A","explanation":"Division of labour leads to the exchange of goods and services as it allows individuals to specialize in specific tasks, increasing efficiency and productivity. This specialization enables the production of surplus goods, which can then be exchanged in the market.","marks":"1","difficulty":"2"},{"id":"objective>Economics>1993>39","subject":"Economics","year":"1993","type":"Objective","topic":"BUSINESS ORGANISATION : SOLE PROPRIETOSHIP","question":"One-man business are popular in West Africa because of all of the following, except the","images":[],"options":{"A":"ease of entry","B":"small capital required","C":"limited entrepreneurial skill needed","D":"tendency to become joint stock company"},"answer":"D","explanation":"One-man businesses are popular in West Africa due to factors like ease of entry, small capital requirements, limited entrepreneurial skills needed, and ease of decision-making. However, the tendency to become a joint stock company is not a reason for their popularity; rather, it is often the opposite, as one-man businesses typically remain small and do not transition into joint stock companies.","marks":"1","difficulty":"2"},{"id":"objective>Economics>1993>40","subject":"Economics","year":"1993","type":"Objective","topic":"BUSINESS ORGANISATION : PUBLIC CORPORATIONS","question":"Which of the following is not a reason why statutory corporations are run only by the government?","images":[],"options":{"A":"The duplication of some services will lead to resource wastage","B":"All corporations provide services which individuals cannot provide","C":"Essential services must be provided irrespective of the economic system adopted","D":"Some corporations require large financial capital which may not be easy to  acquire by individuals"},"answer":"A","explanation":"The duplication of some services leading to resource wastage is not a reason why statutory corporations are run only by the government. Statutory corporations are typically established to provide essential services that may not be profitable for private entities, protect consumers, and ensure that large-scale services requiring significant capital are managed effectively. The concern about resource wastage is more relevant to the efficiency of service delivery rather than a justification for government operation.","marks":"1","difficulty":"3"}];